import { Tabs as TabsPrimitive } from "@base-ui/react/tabs";
import { useTabsStyles } from "./tabs-root";

interface TabsPanelProps extends TabsPrimitive.Panel.Props {
  className?: string;
}

export function TabsPanel({ className, ...props }: TabsPanelProps) {
  const styles = useTabsStyles();
  return <TabsPrimitive.Panel {...props} className={styles.panel({ class: className })} data-slot="tabs-panel" />;
}

import { tv } from "@/registry/bare/lib/tv.config";

export const tabsStyles = tv({
  slots: {
    root: [""],
    list: [""],
    tab: [""],
    indicator: [""],
    panel: [""],
  },
});

export { TabsRoot as Root } from "./tabs-root";
export { TabsList as List } from "./tabs-list";
export { TabsTab as Tab } from "./tabs-tab";
export { TabsIndicator as Indicator } from "./tabs-indicator";
export { TabsPanel as Panel } from "./tabs-panel";
